datasource db {
  provider = "sqlite"
  url      = "file:./dev.db"
}

model User {
  id       String @id @default(uuid())
  email    String @unique
  password String
  role     String @default("USER")
}

model Restaurant {
  id       String     @id @default(uuid())
  name     String
  menuItems MenuItem[]
  orders    Order[]
}

model MenuItem {
  id           String     @id @default(uuid())
  name         String
  price        Float
  restaurantId String
  restaurant   Restaurant @relation(fields: [restaurantId], references: [id])
  orderItems   OrderItem[]
}

model Order {
  id           String      @id @default(uuid())
  restaurantId String
  restaurant   Restaurant  @relation(fields: [restaurantId], references: [id])
  items        OrderItem[]
  status       String      @default("PENDING")
}

model OrderItem {
  id         String   @id @default(uuid())
  orderId    String
  order      Order    @relation(fields: [orderId], references: [id])
  menuItemId String
  menuItem   MenuItem @relation(fields: [menuItemId], references: [id])
  quantity   Int
}
"}

